import{_ as s,o as a,c as e,ae as l}from"./chunks/framework.6gkcVjOI.js";const d=JSON.parse('{"title":"Architecture Overview","description":"High-level architecture of go-code — components, data flow, and design philosophy","frontmatter":{"title":"Architecture Overview","description":"High-level architecture of go-code — components, data flow, and design philosophy"},"headers":[],"relativePath":"architecture/overview.md","filePath":"architecture/overview.md","lastUpdated":1775195864000}'),p={name:"architecture/overview.md"};function i(r,n,t,o,c,b){return a(),e("div",null,[...n[0]||(n[0]=[l(`<h1 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h1><p>go-code is a Go implementation of Anthropic&#39;s Claude Code agent system. It combines a large language model (LLM) with a robust execution harness to enable autonomous software engineering tasks.</p><h2 id="high-level-architecture" tabindex="-1">High-Level Architecture <a class="header-anchor" href="#high-level-architecture" aria-label="Permalink to &quot;High-Level Architecture&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                              go-code                                │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                                                     │</span></span>
<span class="line"><span>│  ┌──────────────┐    ┌──────────────┐    ┌───────────────────────┐ │</span></span>
<span class="line"><span>│  │   CLI/Repl   │───▶│  Agent Loop  │───▶│    Tool Registry     │ │</span></span>
<span class="line"><span>│  └──────────────┘    └──────────────┘    └───────────────────────┘ │</span></span>
<span class="line"><span>│                            │                         │              │</span></span>
<span class="line"><span>│                            ▼                         ▼              │</span></span>
<span class="line"><span>│                     ┌──────────────┐         ┌───────────────────┐  │</span></span>
<span class="line"><span>│                     │  API Client  │         │   Built-in Tools  │  │</span></span>
<span class="line"><span>│                     │   (Stream)   │         │  Bash, Read,      │  │</span></span>
<span class="line"><span>│                     └──────────────┘         │  Write, Edit,     │  │</span></span>
<span class="line"><span>│                            │                 │  Glob, Grep       │  │</span></span>
<span class="line"><span>│                            ▼                 └───────────────────┘  │</span></span>
<span class="line"><span>│                     ┌──────────────┐                                │</span></span>
<span class="line"><span>│                     │  Anthropic   │                                │</span></span>
<span class="line"><span>│                     │     API      │                                │</span></span>
<span class="line"><span>│                     └──────────────┘                                │</span></span>
<span class="line"><span>│                                                                     │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  ┌──────────────┐    ┌──────────────┐    ┌───────────────────────┐ │</span></span>
<span class="line"><span>│  │    Config    │    │  Permission  │    │    MCP Integration   │ │</span></span>
<span class="line"><span>│  │    Loader   │    │    System    │    │       (Adapter)       │ │</span></span>
<span class="line"><span>│  └──────────────┘    └──────────────┘    └───────────────────────┘ │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br></div></div><h2 id="component-breakdown" tabindex="-1">Component Breakdown <a class="header-anchor" href="#component-breakdown" aria-label="Permalink to &quot;Component Breakdown&quot;">​</a></h2><h3 id="_1-cli-repl" tabindex="-1">1. CLI/RePL <a class="header-anchor" href="#_1-cli-repl" aria-label="Permalink to &quot;1. CLI/RePL&quot;">​</a></h3><p>The command-line interface provides the user-facing entry point:</p><ul><li>Parses command-line arguments</li><li>Manages interactive REPL sessions</li><li>Streams user input to the agent</li><li>Displays output and tool execution results</li></ul><p><strong>Location</strong>: <code>pkg/tty/repl.go</code></p><h3 id="_2-agent-loop" tabindex="-1">2. Agent Loop <a class="header-anchor" href="#_2-agent-loop" aria-label="Permalink to &quot;2. Agent Loop&quot;">​</a></h3><p>The core orchestrator managing the think → act → observe execution cycle:</p><ul><li>Maintains conversation history</li><li>Sends requests to the API with tools and context</li><li>Processes model responses and stop reasons</li><li>Executes tools and feeds results back to the model</li><li>Manages the loop until the task completes</li></ul><p><strong>Location</strong>: <code>internal/agent/loop.go</code></p><h3 id="_3-api-client" tabindex="-1">3. API Client <a class="header-anchor" href="#_3-api-client" aria-label="Permalink to &quot;3. API Client&quot;">​</a></h3><p>Handles communication with the Anthropic API:</p><ul><li>Sends messages with tool definitions</li><li>Receives streaming responses</li><li>Parses tool call requests from the model</li><li>Manages authentication</li></ul><p><strong>Location</strong>: <code>internal/api/client.go</code>, <code>internal/api/stream.go</code></p><h3 id="_4-tool-registry" tabindex="-1">4. Tool Registry <a class="header-anchor" href="#_4-tool-registry" aria-label="Permalink to &quot;4. Tool Registry&quot;">​</a></h3><p>Central registry for all available tools:</p><ul><li>Manages built-in tool registration</li><li>Handles MCP tool discovery</li><li>Provides tool schemas to the model</li><li>Routes tool calls to appropriate implementations</li></ul><p><strong>Location</strong>: <code>internal/tool/registry.go</code></p><h3 id="_5-built-in-tools" tabindex="-1">5. Built-in Tools <a class="header-anchor" href="#_5-built-in-tools" aria-label="Permalink to &quot;5. Built-in Tools&quot;">​</a></h3><p>Six core tools that enable file system and command execution:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th><th>Permission Required</th></tr></thead><tbody><tr><td><strong>Read</strong></td><td>Read file contents</td><td>No</td></tr><tr><td><strong>Write</strong></td><td>Create or overwrite files</td><td>Yes</td></tr><tr><td><strong>Edit</strong></td><td>Make targeted modifications</td><td>Yes</td></tr><tr><td><strong>Glob</strong></td><td>Find files by pattern</td><td>No</td></tr><tr><td><strong>Grep</strong></td><td>Search file contents</td><td>No</td></tr><tr><td><strong>Bash</strong></td><td>Execute shell commands</td><td>Yes</td></tr></tbody></table><p><strong>Location</strong>: <code>internal/tool/builtin/</code></p><h3 id="_6-permission-system" tabindex="-1">6. Permission System <a class="header-anchor" href="#_6-permission-system" aria-label="Permalink to &quot;6. Permission System&quot;">​</a></h3><p>Ensures user control over dangerous operations:</p><ul><li>Intercepts potentially harmful tool calls</li><li>Prompts for user approval</li><li>Manages auto-approval policies</li><li>Logs permission decisions</li></ul><p><strong>Location</strong>: <code>internal/permission/</code></p><h3 id="_7-config-loader" tabindex="-1">7. Config Loader <a class="header-anchor" href="#_7-config-loader" aria-label="Permalink to &quot;7. Config Loader&quot;">​</a></h3><p>Loads and manages configuration:</p><ul><li>Reads JSON config files</li><li>Processes environment variables</li><li>Applies config precedence rules</li></ul><p><strong>Location</strong>: <code>internal/config/loader.go</code></p><h3 id="_8-mcp-integration" tabindex="-1">8. MCP Integration <a class="header-anchor" href="#_8-mcp-integration" aria-label="Permalink to &quot;8. MCP Integration&quot;">​</a></h3><p>Provides Model Context Protocol support:</p><ul><li>MCP server discovery</li><li>Tool adapter for MCP tools</li><li>Transport layer management</li></ul><p><strong>Location</strong>: <code>internal/tool/mcp/</code></p><h2 id="data-flow" tabindex="-1">Data Flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data Flow&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User Input</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        Agent Loop                               │</span></span>
<span class="line"><span>│  1. Add user message to history                                │</span></span>
<span class="line"><span>│  2. Compact history if needed                                  │</span></span>
<span class="line"><span>│  3. Build API request (tools + messages)                       │</span></span>
<span class="line"><span>└──────────────────────────┬──────────────────────────────────────┘</span></span>
<span class="line"><span>                           │</span></span>
<span class="line"><span>                           ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                      API Client                                 │</span></span>
<span class="line"><span>│  4. Send request to Anthropic API (streaming)                  │</span></span>
<span class="line"><span>└──────────────────────────┬──────────────────────────────────────┘</span></span>
<span class="line"><span>                           │</span></span>
<span class="line"><span>                           ▼</span></span>
<span class="line"><span>                    ┌──────────────┐</span></span>
<span class="line"><span>                    │ Anthropic    │</span></span>
<span class="line"><span>                    │     API      │</span></span>
<span class="line"><span>                    └──────┬───────┘</span></span>
<span class="line"><span>                           │</span></span>
<span class="line"><span>                           ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        Agent Loop                               │</span></span>
<span class="line"><span>│  5. Process response based on stop_reason:                     │</span></span>
<span class="line"><span>│     - end_turn: Return final response                          │</span></span>
<span class="line"><span>│     - tool_use: Execute tools and continue                     │</span></span>
<span class="line"><span>│     - max_tokens: Return truncated response                    │</span></span>
<span class="line"><span>└──────────────────────────┬──────────────────────────────────────┘</span></span>
<span class="line"><span>                           │</span></span>
<span class="line"><span>                    ┌──────▼───────┐</span></span>
<span class="line"><span>                    │   Execute    │</span></span>
<span class="line"><span>                    │    Tools     │</span></span>
<span class="line"><span>                    └──────┬───────┘</span></span>
<span class="line"><span>                           │</span></span>
<span class="line"><span>                           ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                   Permission System                             │</span></span>
<span class="line"><span>│  6. Check if tool requires permission                          │</span></span>
<span class="line"><span>│  7. Prompt user if needed                                      │</span></span>
<span class="line"><span>└──────────────────────────┬──────────────────────────────────────┘</span></span>
<span class="line"><span>                           │</span></span>
<span class="line"><span>                           ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    Tool Registry                                │</span></span>
<span class="line"><span>│  8. Route to appropriate tool (built-in or MCP)               │</span></span>
<span class="line"><span>│  9. Execute tool and capture result                            │</span></span>
<span class="line"><span>└──────────────────────────┬──────────────────────────────────────┘</span></span>
<span class="line"><span>                           │</span></span>
<span class="line"><span>                           ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        Agent Loop                               │</span></span>
<span class="line"><span>│  10. Add tool results to history                               │</span></span>
<span class="line"><span>│  11. Continue loop (back to step 2)                            │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br><span class="line-number">47</span><br><span class="line-number">48</span><br><span class="line-number">49</span><br><span class="line-number">50</span><br><span class="line-number">51</span><br><span class="line-number">52</span><br><span class="line-number">53</span><br><span class="line-number">54</span><br><span class="line-number">55</span><br><span class="line-number">56</span><br></div></div><h2 id="design-philosophy" tabindex="-1">Design Philosophy <a class="header-anchor" href="#design-philosophy" aria-label="Permalink to &quot;Design Philosophy&quot;">​</a></h2><p>go-code follows a clear separation of concerns:</p><h3 id="model-provides-intelligence" tabindex="-1">Model Provides Intelligence <a class="header-anchor" href="#model-provides-intelligence" aria-label="Permalink to &quot;Model Provides Intelligence&quot;">​</a></h3><p>The LLM (Claude) is responsible for:</p><ul><li>Understanding user intent</li><li>Deciding which tools to use</li><li>Interpreting tool results</li><li>Generating natural language responses</li></ul><h3 id="harness-provides-reliability" tabindex="-1">Harness Provides Reliability <a class="header-anchor" href="#harness-provides-reliability" aria-label="Permalink to &quot;Harness Provides Reliability&quot;">​</a></h3><p>The Go runtime provides:</p><ul><li>Tool execution and safety</li><li>Conversation history management</li><li>Permission enforcement</li><li>Configuration management</li><li>Error handling and recovery</li></ul><p>This division allows the model to focus on the cognitive task while the harness ensures reliable, safe execution.</p><h2 id="directory-structure" tabindex="-1">Directory Structure <a class="header-anchor" href="#directory-structure" aria-label="Permalink to &quot;Directory Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>internal/</span></span>
<span class="line"><span>├── agent/           # Agent loop implementation</span></span>
<span class="line"><span>│   ├── loop.go     # Main loop logic</span></span>
<span class="line"><span>│   └── history.go  # Message history management</span></span>
<span class="line"><span>├── api/            # Anthropic API client</span></span>
<span class="line"><span>│   ├── client.go   # HTTP client</span></span>
<span class="line"><span>│   ├── stream.go   # Streaming handling</span></span>
<span class="line"><span>│   └── types.go    # API types</span></span>
<span class="line"><span>├── config/         # Configuration</span></span>
<span class="line"><span>│   ├── loader.go   # Config file loading</span></span>
<span class="line"><span>│   └── types.go    # Config types</span></span>
<span class="line"><span>├── permission/    # Permission system</span></span>
<span class="line"><span>│   ├── policy.go   # Permission policies</span></span>
<span class="line"><span>│   ├── rules.go    # Permission rules</span></span>
<span class="line"><span>│   └── prompter.go # User prompts</span></span>
<span class="line"><span>└── tool/           # Tool system</span></span>
<span class="line"><span>    ├── registry.go    # Tool registry</span></span>
<span class="line"><span>    ├── tool.go        # Tool interface</span></span>
<span class="line"><span>    ├── init/          # Tool initialization</span></span>
<span class="line"><span>    ├── builtin/       # Built-in tools</span></span>
<span class="line"><span>    │   ├── read.go    # File reading</span></span>
<span class="line"><span>    │   ├── write.go   # File writing</span></span>
<span class="line"><span>    │   ├── edit.go    # File editing</span></span>
<span class="line"><span>    │   ├── glob.go    # File globbing</span></span>
<span class="line"><span>    │   ├── grep.go    # Content search</span></span>
<span class="line"><span>    │   └── bash.go    # Shell execution</span></span>
<span class="line"><span>    └── mcp/           # MCP integration</span></span>
<span class="line"><span>        ├── adapter.go # MCP tool adapter</span></span>
<span class="line"><span>        ├── client.go  # MCP client</span></span>
<span class="line"><span>        ├── config.go  # MCP configuration</span></span>
<span class="line"><span>        └── transport.go# MCP transport</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br></div></div><h2 id="related-documentation" tabindex="-1">Related Documentation <a class="header-anchor" href="#related-documentation" aria-label="Permalink to &quot;Related Documentation&quot;">​</a></h2><ul><li><a href="./agent-loop.html">Agent Loop Deep Dive</a> — Detailed execution cycle explanation</li><li><a href="./tools.html">Tool System</a> — Tool implementations and extension</li><li><a href="./../guide/quick-start.html">Quick Start Guide</a> — Running go-code</li></ul>`,52)])])}const m=s(p,[["render",i]]);export{d as __pageData,m as default};
